using var bitmap = SKBitmap.Decode(imageData);
Console.WriteLine($"Original: {bitmap.Width}x{bitmap.Height}, RowBytes={bitmap.RowBytes}");

using var bitmapSubset = new SKBitmap();
if (!bitmap.ExtractSubset(bitmapSubset, SKRectI.Create(bitmap.Width - 25, bitmap.Height - 25, 25, 25)))
    throw new InvalidOperationException("Unable to create subset!");

Console.WriteLine($"Subset: {bitmapSubset.Width}x{bitmapSubset.Height}, RowBytes={bitmapSubset.RowBytes}");

var pixmap = bitmapSubset.PeekPixels();
var pixmapInfo = pixmap.Info;
var pixmapBytes = pixmap.GetPixelSpan();
Console.WriteLine($"GetPixelSpan() length: {pixmapBytes.Length}");

var expected = pixmapInfo.Height > 0
    ? ((pixmap.RowBytes * (pixmapInfo.Height - 1)) + pixmapInfo.RowBytes) : 0;
Console.WriteLine($"Expected: {expected}");

if (pixmapBytes.Length < expected)
{
    Console.WriteLine($"BUG: span is {expected - pixmapBytes.Length} bytes too short");
    Environment.Exit(1);
}
else
    Console.WriteLine("SUCCESS");
